    rec_rate = 1.0 / rec
    slow_rec_rate = 1.0 / slow_rec

    util = send / rec
    st["util_ema"] = 0.85 * st["util_ema"] + 0.15 * util
    st["q_ema"] = 0.9 * st["q_ema"] + 0.1 * rtt_ratio
    dr = rtt_ratio - st["last_rtt"]
    st["trend"] = 0.8 * st["trend"] + 0.2 * dr
    st["last_rtt"] = rtt_ratio

    if st["base_rec"] is None:
        st["base_rec"] = rec
    else:
        st["base_rec"] = min(st["base_rec"] * 1.0005, rec)
    if st["base_send"] is None:
        st["base_send"] = send
    else:
        st["base_send"] = min(st["base_send"] * 1.0005, send)

    low_q = rtt_ratio < 1.15 and st["q_ema"] < 1.2
    heavy_q = rtt_ratio > 2.0 or st["q_ema"] > 2.1

    if st["phase"] == "startup":
        if heavy_q or st["trend"] > 0.06:
            st["phase"] = "drain"
        elif rtt_ratio > 1.35 and st["util_ema"] > 1.05:
