        st["cong_events"] += 1
        mult = 0.55 if heavy_q else 0.72
        target_rate = rec_rate * (0.82 if heavy_q else 0.9)
        intersend = 1.0 / max(target_rate, 1e-6)
        return RemyAction(window_increment=0, window_multiple=mult, intersend=intersend)

