            mult = 0.94
    else:
        inc = -1
        mult = 0.85 if rtt_ratio < 2.0 else 0.7

    if rtt_ratio < 1.3 and inc <= 0:
        inc = 1
        mult = max(mult, 1.0)

    gain = 1.0 + max(min(0.35 * util_err - 0.45 * q_err - 0.4 * st["trend"], 0.25), -0.25)
    target_rate = rec_rate * gain
    target_rate = max(min(target_rate, send_rate * 1.35), send_rate * 0.7)
    intersend = 1.0 / max(target_rate, 1e-6)

