    if st["base_send"] is None:
        st["base_send"] = send

    st["base_rec"] = 0.995 * st["base_rec"] + 0.005 * rec
    st["base_send"] = 0.995 * st["base_send"] + 0.005 * send

    queue_pressure = max(0.0, rtt - 1.0)
    rate_mismatch = (rec / send) - 1.0
    grad = (rec - slow_rec) / slow_rec
    st["trend"] = 0.85 * st["trend"] + 0.15 * grad

    if rtt > 2.0:
        st["cong"] = min(20, st["cong"] + 1)
        st["relief"] = 0
    elif rtt < 1.25:
        st["relief"] = min(20, st["relief"] + 1)
        st["cong"] = max(0, st["cong"] - 1)
    else:
        st["cong"] = max(0, st["cong"] - 1)
        st["relief"] = max(0, st["relief"] - 1)

