        gain = 1.04 + 0.08 * max(0.0, 1.2 - rtt)
        gain *= 1.0 + 0.05 * max(0.0, -st["trend"])
        gain = min(1.22, max(1.02, gain))
        target_rate = max(recv_rate, slow_recv_rate) * gain
        intersend = max(0.0, 1.0 / max(target_rate, 1e-6))
        return RemyAction(window_increment=grow, window_multiple=1.0, intersend=intersend)

    if rtt > 1.7:
        sev = min(1.0, (rtt - 1.7) / 0.5)
        wm = 1.0 - 0.18 * sev
        wm = max(0.78, min(0.96, wm))
        target_rate = recv_rate * (0.95 - 0.15 * sev)
        intersend = max(0.0, 1.0 / max(target_rate, 1e-6))
        return RemyAction(window_increment=0, window_multiple=wm, intersend=intersend)

    if rtt > 1.3:
        sev = (rtt - 1.3) / 0.4
        sev = min(1.0, max(0.0, sev))
        if st["trend"] > 0.04 or rate_mismatch > 0.25:
            inc = -1
            wm = 1.0
        else:
            inc = 0
            wm = 1.0 - 0.05 * sev
        target_gain = 1.0 - 0.08 * sev
        target_gain = min(1.02, max(0.9, target_gain))
        target_rate = recv_rate * target_gain
        intersend = max(0.0, 1.0 / max(target_rate, 1e-6))
        return RemyAction(window_increment=inc, window_multiple=wm, intersend=intersend)

    target_rate = recv_rate * 1.02
    intersend = max(0.0, 1.0 / max(target_rate, 1e-6))
    return RemyAction(window_increment=1, window_multiple=1.0, intersend=intersend)

