        headroom = max(0.0, 1.0 - min(1.0, congestion / 0.35))
        gain = 1.01 + 0.08 * headroom
        if st["util_ema"] > 1.05:
            gain *= 0.98
        elif st["util_ema"] < 0.95:
            gain *= 1.04
        target_rate = max(1e-6, st["bw_ema"] * gain)
        intersend = max(0.0, min(7.0, 1.0 / target_rate))
        inc = 1
        if headroom > 0.75 and st["good"] > 5 and st["cooldown"] == 0:
            inc = 3
        elif headroom > 0.4:
            inc = 2
        return RemyAction(window_increment=inc, window_multiple=1.0, intersend=intersend)

    if st["cooldown"] > 0:
        target_rate = max(1e-6, st["bw_ema"] * 0.92)
        intersend = max(0.0, min(10.0, 1.0 / target_rate))
        return RemyAction(window_increment=0, window_multiple=0.96, intersend=intersend)

    if congestion > 0.5 or rtt > 1.75:
        sev = min(1.0, (congestion - 0.5) / 0.7) if congestion > 0.5 else min(1.0, (rtt - 1.75) / 0.6)
        mult = 0.9 - 0.18 * sev
        target_rate = max(1e-6, st["bw_ema"] * (0.9 - 0.12 * sev))
        intersend = max(0.0, min(10.0, 1.0 / target_rate))
        st["cooldown"] = 2
        return RemyAction(window_increment=-1, window_multiple=mult, intersend=intersend)

    if congestion > 0.22 or rtt > 1.45:
        sev = min(1.0, max((congestion - 0.22) / 0.35, (rtt - 1.45) / 0.4))
        mult = 0.98 - 0.06 * sev
        target_rate = max(1e-6, st["bw_ema"] * (0.98 - 0.05 * sev))
        intersend = max(0.0, min(9.0, 1.0 / target_rate))
        return RemyAction(window_increment=0, window_multiple=mult, intersend=intersend)

    target_rate = max(1e-6, st["bw_ema"] * 1.01)
    intersend = max(0.0, min(8.0, 1.0 / target_rate))
    return RemyAction(window_increment=1, window_multiple=1.0, intersend=intersend)

def evolved_policy(memory):
    from alphacc.remy_eval import RemyAction
    import math

    if not hasattr(evolved_policy, "_state"):
        evolved_policy._state = {
            "phase": "startup",
            "rtt_base": max(1.0, float(memory.rtt_ratio) if memory.rtt_ratio > 0 else 1.0),
            "rtt_ema": max(1.0, float(memory.rtt_ratio) if memory.rtt_ratio > 0 else 1.0),
            "trend": 0.0,
            "util_ema": 1.0,
            "last_intersend": 0.0,
            "cooldown": 0,
            "over_cnt": 0,
            "under_cnt": 0,
        }
    st = evolved_policy._state

    send = max(1e-6, float(memory.send_ewma) if memory.send_ewma > 0 else 1e-6)
    rec = max(1e-6, float(memory.rec_ewma) if memory.rec_ewma > 0 else 1e-6)
    slow_rec_raw = float(memory.slow_rec_ewma) if memory.slow_rec_ewma > 0 else rec
    slow_rec = max(1e-6, slow_rec_raw)
    rtt = max(1.0, float(memory.rtt_ratio) if memory.rtt_ratio > 0 else 1.0)

    send_rate = 1.0 / send
    rec_rate = 1.0 / rec
    slow_rec_rate = 1.0 / slow_rec

    util = send / rec
    st["util_ema"] = 0.88 * st["util_ema"] + 0.12 * util
    st["rtt_ema"] = 0.90 * st["rtt_ema"] + 0.10 * rtt
    st["rtt_base"] = min(st["rtt_base"], rtt) * 0.999 + st["rtt_base"] * 0.001
    st["rtt_base"] = min(st["rtt_base"], st["rtt_ema"])
    q = max(0.0, st["rtt_ema"] - st["rtt_base"])
    st["trend"] = 0.82 * st["trend"] + 0.18 * (rtt - st["rtt_ema"])

    if rtt > 1.6:
        st["over_cnt"] += 1
    else:
        st["over_cnt"] = max(0, st["over_cnt"] - 1)

    if rtt < 1.15 and util < 1.05:
        st["under_cnt"] += 1
    else:
        st["under_cnt"] = max(0, st["under_cnt"] - 1)

    if st["cooldown"] > 0:
        st["cooldown"] -= 1

    if st["phase"] == "startup":
        if rtt > 1.28 or util > 1.18:
            st["phase"] = "drain"
            st["cooldown"] = 3
        else:
            gain = 1.18 if rtt < 1.10 else 1.10
            target_rate = max(send_rate * 1.02, rec_rate * gain)
            intersend = 1.0 / max(1e-6, target_rate)
            if st["last_intersend"] > 0:
                intersend = 0.70 * st["last_intersend"] + 0.30 * intersend
            st["last_intersend"] = intersend
            return RemyAction(window_increment=4, window_multiple=1.0, intersend=intersend)

    if st["phase"] == "drain":
        sev = min(1.0, max(0.0, (rtt - 1.15) / 0.85))
        mult = 0.93 - 0.28 * sev
        if rtt > 2.0:
            mult = min(mult, 0.58)
        target_rate = max(1e-6, slow_rec_rate * (0.94 - 0.18 * sev))
        intersend = 1.0 / target_rate
        if st["last_intersend"] > 0:
            intersend = 0.60 * st["last_intersend"] + 0.40 * intersend
        st["last_intersend"] = intersend

        if rtt < 1.14 and st["util_ema"] < 1.08:
            st["phase"] = "steady"
            return RemyAction(window_increment=1, window_multiple=0.98, intersend=intersend)
        return RemyAction(window_increment=0, window_multiple=mult, intersend=intersend)

    # steady
    pressure = 0.75 * max(0.0, rtt - 1.0) + 0.55 * max(0.0, st["util_ema"] - 1.0) + 0.45 * max(0.0, st["trend"])

    if rtt > 2.0:
        sev = min(1.0, (rtt - 2.0) / 1.5)
        mult = 0.62 - 0.22 * sev
        target_rate = max(1e-6, slow_rec_rate * (0.82 - 0.12 * sev))
        intersend = 1.0 / target_rate
        if st["last_intersend"] > 0:
            intersend = 0.55 * st["last_intersend"] + 0.45 * intersend
        st["last_intersend"] = intersend
        st["cooldown"] = 3
        return RemyAction(window_increment=0, window_multiple=mult, intersend=intersend)

    if rtt < 1.3:
        headroom = max(0.0, 1.3 - rtt)
        gain = 1.02 + 0.22 * min(1.0, headroom / 0.3)
        gain *= 1.0 + 0.08 * max(0.0, 1.0 - util)
        gain = min(1.30, max(1.01, gain))

        if pressure < 0.10:
            inc = 4 if rtt < 1.10 else 3
        elif pressure < 0.20:
            inc = 2
        else:
            inc = 1  # must stay >0 for rtt<1.3

        if st["cooldown"] > 0:
            inc = max(1, inc - 1)
            gain = min(gain, 1.08)

        target_rate = max(send_rate * 1.01, rec_rate * gain)
        intersend = 1.0 / max(1e-6, target_rate)
        if st["last_intersend"] > 0:
            intersend = 0.78 * st["last_intersend"] + 0.22 * intersend
        st["last_intersend"] = intersend
        return RemyAction(window_increment=inc, window_multiple=1.0, intersend=intersend)

    # 1.3 <= rtt <= 2.0 proportional control
    sev = min(1.0, max(0.0, (rtt - 1.3) / 0.7))
    mult = 1.0 - (0.10 + 0.16 * sev + 0.08 * max(0.0, st["trend"]))
    mult = max(0.72, min(0.99, mult))

    if sev < 0.35:
        inc = 1
    elif sev < 0.75:
        inc = 0
    else:
        inc = -1

    if st["cooldown"] > 0:
        mult = min(mult, 0.95)
        inc = min(inc, 0)

    rate_gain = 1.0 - 0.22 * sev - 0.10 * max(0.0, st["trend"])
    rate_gain = max(0.78, min(1.02, rate_gain))
    target_rate = max(1e-6, slow_rec_rate * rate_gain)
    intersend = 1.0 / target_rate
    if st["last_intersend"] > 0:
        intersend = 0.82 * st["last_intersend"] + 0.18 * intersend
    st["last_intersend"] = intersend

    return RemyAction(window_increment=inc, window_multiple=mult, intersend=intersend)

