    return RemyAction(window_increment=int(inc), window_multiple=float(mult), intersend=float(smooth))

def evolved_policy(memory):
    from alphacc.remy_eval import RemyAction
    import math

    if not hasattr(evolved_policy, "_state"):
        evolved_policy._state = {
            "phase": "startup",
            "q_ema": 1.0,
            "q_slope": 0.0,
            "util_ema": 1.0,
            "trend_ema": 1.0,
            "last_intersend": 0.0,
            "over_cnt": 0,
            "under_cnt": 0,
            "cooldown": 0,
        }
    st = evolved_policy._state

    send = max(1e-6, float(memory.send_ewma) if memory.send_ewma > 0 else 1e-6)
    rec = max(1e-6, float(memory.rec_ewma) if memory.rec_ewma > 0 else 1e-6)
    slow_rec = max(1e-6, float(memory.slow_rec_ewma) if memory.slow_rec_ewma > 0 else rec)
    rtt = max(1.0, float(memory.rtt_ratio) if memory.rtt_ratio > 0 else 1.0)

    recv_rate = 1.0 / rec
    send_rate = 1.0 / send
    util = send / rec
    trend = rec / slow_rec

    prev_q = st["q_ema"]
    st["q_ema"] = 0.90 * st["q_ema"] + 0.10 * rtt
    st["q_slope"] = 0.82 * st["q_slope"] + 0.18 * (st["q_ema"] - prev_q)
    st["util_ema"] = 0.86 * st["util_ema"] + 0.14 * util
    st["trend_ema"] = 0.88 * st["trend_ema"] + 0.12 * trend

    q = st["q_ema"]
    qs = st["q_slope"]
    t = st["trend_ema"]

    if rtt > 1.55 or t > 1.035 or qs > 0.015:
        st["over_cnt"] += 1
        st["under_cnt"] = max(0, st["under_cnt"] - 1)
    elif rtt < 1.20 and t < 0.995 and qs <= 0.0:
        st["under_cnt"] += 1
        st["over_cnt"] = max(0, st["over_cnt"] - 1)
    else:
        st["over_cnt"] = max(0, st["over_cnt"] - 1)
        st["under_cnt"] = max(0, st["under_cnt"] - 1)

    if st["cooldown"] > 0:
        st["cooldown"] -= 1

    inc = 0
    mult = 1.0

    if st["phase"] == "startup":
        if rtt < 1.10 and t < 1.01:
            inc = 5
        elif rtt < 1.20:
            inc = 3
        elif rtt < 1.30:
            inc = 2
        else:
            st["phase"] = "drain"
            inc = -1
            mult = 0.88
            st["cooldown"] = 2

    elif st["phase"] == "drain":
        if rtt > 1.25:
            inc = -1
            mult = 0.90 if rtt < 1.6 else 0.82
        else:
            st["phase"] = "probe"
            inc = 1
            mult = 1.0

    else:
        target_q = 1.14
        err = target_q - q
        drive = 9.0 * err - 60.0 * max(0.0, qs) - 7.0 * max(0.0, t - 1.0)

        if st["util_ema"] < 1.03 and rtt < 1.35:
            drive += 0.9
        if t < 0.985 and rtt < 1.28:
            drive += 0.5

        if rtt > 2.4:
            inc = -2
            mult = 0.55
            st["cooldown"] = 3
        elif rtt > 2.0:
            inc = -1
            mult = 0.68
            st["cooldown"] = 2
        elif rtt > 1.7:
            inc = -1
            mult = 0.82
        elif drive >= 2.8:
            inc = 3
            mult = 1.0
        elif drive >= 1.2:
            inc = 2
            mult = 1.0
        elif drive >= 0.2:
            inc = 1
            mult = 1.0
        elif drive > -0.8:
            inc = 0
            mult = 1.0
        elif drive > -2.0:
            inc = 0
            mult = 0.96
        else:
            inc = -1
            mult = 0.90

        if st["over_cnt"] >= 3 and rtt > 1.35 and st["cooldown"] == 0:
            mult = min(mult, 0.90)
            inc = min(inc, 0)
            st["cooldown"] = 2
        if st["under_cnt"] >= 4 and rtt < 1.22:
            inc = max(inc, 2)
            mult = max(mult, 1.0)

    if rtt < 1.3 and inc <= 0:
        inc = 1
        mult = max(mult, 1.0)

    if rtt > 2.0:
        mult = min(mult, 0.75)

    if rtt < 1.08:
        gain = 1.16
    elif rtt < 1.20:
        gain = 1.09
    elif rtt < 1.35:
        gain = 1.03
    elif rtt < 1.60:
        gain = 0.97
    elif rtt < 2.0:
        gain = 0.91
    else:
        gain = 0.84

    gain *= max(0.85, min(1.12, 1.0 - 2.2 * max(0.0, qs)))
    if t > 1.04:
        gain *= 0.93
    elif t < 0.98 and rtt < 1.3:
        gain *= 1.03

    if st["util_ema"] < 1.02 and rtt < 1.3:
        gain *= 1.04
    elif st["util_ema"] > 1.15 and rtt > 1.35:
        gain *= 0.95

    target_rate = max(1e-6, recv_rate * gain)
    intersend = 1.0 / target_rate

    if st["last_intersend"] <= 0.0:
        smooth = intersend
    else:
        alpha = 0.18 if rtt < 1.4 else 0.30
        smooth = (1.0 - alpha) * st["last_intersend"] + alpha * intersend

    floor_is = rec * (0.70 if rtt < 1.18 else 0.82 if rtt < 1.5 else 0.90)
    ceil_is = rec * (1.10 if rtt < 1.4 else 1.25 if rtt < 2.0 else 1.45)
    smooth = min(max(smooth, floor_is), ceil_is)
    smooth = min(max(smooth, 0.0), 2000.0)
    st["last_intersend"] = smooth

    return RemyAction(window_increment=int(inc), window_multiple=float(mult), intersend=float(smooth))
